const input = $input.first().json;
const body = input.body || input;
const data = body.Data || {};
const extra = body.Extra || {};
const stats = data.BackendStatistics || {};
const logLines = body.LogLines || [];

const jobName = extra['backup-name'] || extra.OperationName || 'Unknown Job';
const status = data.ParsedResult || 'Unknown';
const duration = data.Duration || '';
const filesExamined = data.ExaminedFiles || 0;
const filesAdded = data.AddedFiles || 0;
const filesModified = data.ModifiedFiles || 0;
const filesDeleted = data.DeletedFiles || 0;
const filesWithError = data.FilesWithError || 0;
const sizeExamined = data.SizeOfExaminedFiles || 0;
const bytesUploaded = stats.BytesUploaded || 0;
const errorsCount = data.ErrorsActualLength || 0;
const warningsCount = data.WarningsActualLength || 0;
const endTime = data.EndTime || '';
const exception = body.Exception || null;

const warnings = data.Warnings || [];
const errors = data.Errors || [];

const isSuccess = status === 'Success' && errorsCount === 0 && warningsCount === 0;
const isWarning = status === 'Warning' || (warningsCount > 0 && errorsCount === 0);
const isError = status === 'Error' || status === 'Fatal' || errorsCount > 0;

function formatBytes(bytes) {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return (bytes / Math.pow(k, i)).toFixed(1) + ' ' + sizes[i];
}

let color, emoji;
if (isError) { color = 15158332; emoji = '\ud83d\udd34'; }
else if (isWarning) { color = 16776960; emoji = '\u26a0\ufe0f'; }
else { color = 3066993; emoji = '\u2705'; }

let description = `**Status:** ${status}`;
description += `\n**Duration:** ${duration}`;
description += `\n**Files examined:** ${filesExamined}`;
if (filesAdded > 0) description += ` | **Added:** ${filesAdded}`;
if (filesModified > 0) description += ` | **Modified:** ${filesModified}`;
if (filesDeleted > 0) description += ` | **Deleted:** ${filesDeleted}`;
if (filesWithError > 0) description += ` | **With errors:** ${filesWithError}`;
description += `\n**Size examined:** ${formatBytes(sizeExamined)}`;
if (bytesUploaded > 0) description += ` | **Uploaded:** ${formatBytes(bytesUploaded)}`;

if (errorsCount > 0) {
  description += `\n\n\u274c **Errors (${errorsCount}):**`;
  if (errors.length > 0) {
    description += '\n' + errors.slice(0, 5).join('\n').substring(0, 500);
    if (errors.length > 5) description += `\n...and ${errors.length - 5} more`;
  }
}

if (warningsCount > 0) {
  description += `\n\n\u26a0\ufe0f **Warnings (${warningsCount}):**`;
  if (warnings.length > 0) {
    description += '\n' + warnings.slice(0, 5).join('\n').substring(0, 500);
    if (warnings.length > 5) description += `\n...and ${warnings.length - 5} more`;
  }
}

if (exception) {
  description += `\n\n**Exception:** ${String(exception).substring(0, 300)}`;
}

if (logLines.length > 0) {
  const relevantLogs = logLines.filter(l => l).slice(0, 3).join('\n');
  if (relevantLogs) description += `\n\n**Log:**\n${relevantLogs.substring(0, 300)}`;
}

return [{
  json: {
    isSuccess,
    isError,
    isWarning,
    discordBody: {
      embeds: [{
        title: `${emoji} Backup ${status} — ${jobName}`,
        description: description.substring(0, 2000),
        color: color,
        timestamp: endTime || new Date().toISOString()
      }]
    }
  }
}];
